 1→/**
 2→ * CLI: openmnemo search — full-text search over the transcript index.
 3→ */
 4→
 5→import { join } from 'node:path'
 6→import { resolve } from 'node:path'
 7→
 8→import { defaultGlobalTranscriptRoot, searchTranscripts } from '@openmnemo/core'
 9→import type { SearchResult } from '@openmnemo/core'
10→
11→export interface SearchOptions {
12→  query: string
13→  root: string
14→  globalRoot: string
15→  limit: number
16→  format: string
17→}
18→
19→export async function cmdSearch(options: SearchOptions): Promise<number> {
20→  const query = options.query.trim()
21→  if (!query) {
22→    process.stderr.write('--query must not be empty\n')
23→    return 1
24→  }
25→
26→  const globalRoot = options.globalRoot ? resolve(options.globalRoot) : defaultGlobalTranscriptRoot()
27→  const dbPath = join(globalRoot, 'index', 'search.sqlite')
28→
29→  let results: SearchResult[]
30→  try {
31→    results = await searchTranscripts(dbPath, query, options.limit)
32→  } catch (err: unknown) {
33→    const msg = err instanceof Error ? err.message : String(err)
34→    process.stderr.write(`search error: ${msg}\n`)
35→    return 1
36→  }
37→
38→  if (options.format === 'json') {
39→    process.stdout.write(JSON.stringify({ query, results, count: results.length }) + '\n')
40→  } else {
41→    process.stdout.write(formatSearchText(query, results) + '\n')
42→  }
43→  return 0
44→}
45→
46→function formatSearchText(query: string, results: SearchResult[]): string {
47→  const lines: string[] = [`query: ${query}`, `count: ${results.length}`]
48→  if (results.length > 0) {
49→    lines.push('results:')
50→    for (const r of results) {
51→      lines.push(`- [${r.client}] ${r.project}/${r.session_id}`)
52→      lines.push(`  title: ${r.title}`)
53→      lines.push(`  started_at: ${r.started_at}`)
54→      if (r.cwd) lines.push(`  cwd: ${r.cwd}`)
55→    }
56→  }
57→  return lines.join('\n')
58→}
59→

